create table if not exists public.budgets (budget_id uuid primary key default gen_random_uuid(), trip_id uuid not null references public.trips(id) on delete cascade, total_budget numeric not null, currency text not null, category_budgets jsonb not null default '{}'::jsonb, unique(trip_id));
create table if not exists public.travel_wallets (wallet_id uuid primary key default gen_random_uuid(), trip_id uuid not null references public.trips(id) on delete cascade, method_id text not null, name text not null, currency text not null, initial_amount numeric not null default 0, balance numeric not null default 0, created_at timestamptz not null default now());
create table if not exists public.wallet_transactions (transaction_id uuid primary key default gen_random_uuid(), wallet_id uuid not null references public.travel_wallets(wallet_id) on delete cascade, type text not null, amount numeric not null, expense_id uuid, created_at timestamptz not null default now());
